const BASE_PREMIUMS: Record<string, number> = {
    sword: 100,
    amulet: 60,
    staff: 80,
    potion: 40,
    rune: 25,
    moonstone: 25,
  };

export function processScenario(input: ScenarioInput): { results: unknown[] } {
  const results: unknown[] = [];
  for (const step of input.steps) {
    if (step.op === "quote") {
      if (step.items.length === 0) {
        results.push({ premium: 5 });
      } else if (step.items.length === 1) {
        const item = step.items[0];
        const basePremium = BASE_PREMIUMS[item.type] ?? 0;
        results.push({ premium: basePremium });
      } else {
        results.push({ premium: 0 });
      }
    }
  }
  return { results };
}

