const BLOCK_SIZE = 3;
  const BLOCK_PREMIUM = 60;
  const CURSED_SURCHARGE = 0.5;
  const HIGH_ENCHANTMENT_THRESHOLD = 5;
  const HIGH_ENCHANTMENT_SURCHARGE = 0.3;

  function calculateComponentPremium(items: Array<{ type: string }>): number {
    const byType = items.reduce((acc, item) => {
      acc[item.type] = (acc[item.type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    let premium = 0;
    for (const [type, count] of Object.entries(byType)) {
      const remainder = count % BLOCK_SIZE;
      const useBlock = remainder === 0 && count >= BLOCK_SIZE;
      if (useBlock) {
        premium += (count / BLOCK_SIZE) * BLOCK_PREMIUM;
      } else {
        premium += count * (BASE_PREMIUMS[type] ?? 0);
      }
    }
    return premium;
  }

  function calculateItemPremium(item: { type: string; material?: string; enchantment?: number; cursed?: boolean }): number {
    let basePremium = BASE_PREMIUMS[item.type] ?? 0;
    if (item.cursed) {
      basePremium += basePremium * CURSED_SURCHARGE;
    }
    if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
      basePremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE;
    }
    return basePremium;
  }

