interface ScenarioInput {
  customer: { yearsWithMHPCO: number };
  steps: Array<{
    op: "quote";
    items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>;
  } | {
    op: "claim";
    policy: number;
    incident: { cause: string; damages: Array<{ itemType: string; amount: number }> };
  }>;
}

const BASE_PREMIUMS: Record<string, number> = {
    sword: 100,
    amulet: 60,
    staff: 80,
    potion: 40,
    rune: 25,
    moonstone: 25,
  };

input.newString:
function calculateItemPremium(item: { type: string; material?: string; enchantment?: number; cursed?: boolean }): number {
    let basePremium = BASE_PREMIUMS[item.type] ?? 0;
    if (item.cursed) {
      basePremium += BASE_PREMIUMS[item.type] * CURSED_SURCHARGE;
    }
    if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
      basePremium += BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE;
    }
    return basePremium;
  }

  function calculateQuotePremium(items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>, quoteIndex: number): number {
    if (items.length === 0) {
      return 5;
    }

    let policyBasePremium = 0;
    for (const item of items) {
      policyBasePremium += calculateItemPremium(item);
    }

    const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE;
    const followupDiscount = quoteIndex > 0 ? policyBasePremium * FOLLOWUP_DISCOUNT : 0;

    let premium = policyBasePremium + firstInsuranceSurcharge - followupDiscount + PROCESSING_FEE;
    return Math.ceil(premium);
  }

export function processScenario(input: ScenarioInput): { results: unknown[] } {
  const results: unknown[] = [];
  for (let i = 0; i < input.steps.length; i++) {
    const step = input.steps[i];
    if (step.op === "quote") {
      const premium = calculateQuotePremium(step.items, i);
      results.push({ premium });
    }
  }
  return { results };
}

