function calculateItemPremium(item: { type: string; material?: string; enchantment?: number; cursed?: boolean }): number {
    let basePremium = BASE_PREMIUMS[item.type] ?? 0;
    if (item.cursed) {
      basePremium += BASE_PREMIUMS[item.type] * CURSED_SURCHARGE;
    }
    if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
      basePremium += BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE;
    }
    return basePremium;
  }

export function processScenario(input: ScenarioInput): { results: unknown[] } {
  const results: unknown[] = [];
  for (const step of input.steps) {
    if (step.op === "quote") {
      if (step.items.length === 0) {
        results.push({ premium: 5 });
      } else if (step.items.length === 1) {
        const item = step.items[0];
        const premium = calculateItemPremium(item) * 1.1 + 5;
        results.push({ premium: Math.ceil(premium) });
      } else {
        const components = step.items.filter(i => i.type === "rune" || i.type === "moonstone");
        const nonComponents = step.items.filter(i => i.type !== "rune" && i.type !== "moonstone");
        let premium = 0;
        for (const item of nonComponents) {
          premium += BASE_PREMIUMS[item.type] ?? 0;
        }
        premium += calculateComponentPremium(components);
        results.push({ premium });
      }
    }
  }
  return { results };
}

