function calculateQuotePremium(items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>, quoteIndex: number, customerYears: number): number {
    if (items.length === 0) {
      return 5;
    }

    let policyBasePremium = 0;
    for (const item of items) {
      policyBasePremium += calculateItemPremium(item);
    }

    const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE;
    const followupDiscount = quoteIndex > 0 ? policyBasePremium * FOLLOWUP_DISCOUNT : 0;
    const loyaltyDiscount = customerYears >= LOYALTY_YEARS_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT : 0;

    let premium = policyBasePremium + firstInsuranceSurcharge - followupDiscount - loyaltyDiscount + PROCESSING_FEE;
    return Math.ceil(premium);
  }

export function processScenario(input: ScenarioInput): { results: unknown[] } {
  const results: unknown[] = [];
  for (let i = 0; i < input.steps.length; i++) {
    const step = input.steps[i];
    if (step.op === "quote") {
      const premium = calculateQuotePremium(step.items, i, input.customer.yearsWithMHPCO);
      results.push({ premium });
    }
  }
  return { results };
}

