    const followupDiscount = quoteIndex > 0 ? policyBasePremium * FOLLOWUP_DISCOUNT / 100 : 0;
    const loyaltyDiscount = customerYears >= LOYALTY_YEARS_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT / 100 : 0;

